"""jsonschema_specifications — stub providing JSON Schema meta-schema registry.

Avoids circular imports by using a lazy proxy for REGISTRY that only
builds when first accessed (jsonschema → validators → here → referencing).
"""

__version__ = "2024.10.1"

# JSON Schema meta-schemas (minimal)
_METASCHEMAS = {
    "http://json-schema.org/draft-03/schema#": {
        "$schema": "http://json-schema.org/draft-03/schema#",
        "id": "http://json-schema.org/draft-03/schema#",
        "type": "object",
    },
    "http://json-schema.org/draft-04/schema#": {
        "$schema": "http://json-schema.org/draft-04/schema#",
        "id": "http://json-schema.org/draft-04/schema#",
        "type": "object",
    },
    "http://json-schema.org/draft-06/schema#": {
        "$schema": "http://json-schema.org/draft-06/schema#",
        "$id": "http://json-schema.org/draft-06/schema#",
        "type": "object",
    },
    "http://json-schema.org/draft-07/schema#": {
        "$schema": "http://json-schema.org/draft-07/schema#",
        "$id": "http://json-schema.org/draft-07/schema#",
        "type": "object",
    },
    "https://json-schema.org/draft/2019-09/schema": {
        "$schema": "https://json-schema.org/draft/2019-09/schema",
        "$id": "https://json-schema.org/draft/2019-09/schema",
        "type": ["object", "boolean"],
    },
    "https://json-schema.org/draft/2020-12/schema": {
        "$schema": "https://json-schema.org/draft/2020-12/schema",
        "$id": "https://json-schema.org/draft/2020-12/schema",
        "type": ["object", "boolean"],
    },
}

_REGISTRY_CACHE = None

def _build_registry():
    global _REGISTRY_CACHE
    if _REGISTRY_CACHE is not None:
        return _REGISTRY_CACHE
    import referencing
    import referencing.jsonschema
    try:
        pairs = []
        for uri, schema in _METASCHEMAS.items():
            resource = referencing.Resource.from_contents(
                schema, default_specification=referencing.jsonschema.DRAFT202012
            )
            pairs.append((uri, resource))
        _REGISTRY_CACHE = referencing.Registry().with_resources(pairs)
    except Exception:
        _REGISTRY_CACHE = referencing.Registry()
    return _REGISTRY_CACHE


class _LazyRegistry:
    """Proxy that builds the real registry on first use."""
    def __getattr__(self, name):
        reg = _build_registry()
        return getattr(reg, name)
    def __iter__(self):
        return iter(_build_registry())
    def __len__(self):
        return len(_build_registry())
    def __getitem__(self, key):
        return _build_registry()[key]
    def __contains__(self, key):
        return key in _build_registry()
    def combine(self, *args, **kwargs):
        return _build_registry().combine(*args, **kwargs)
    def contents(self, uri):
        return _build_registry().contents(uri)
    def items(self):
        return _build_registry().items()
    def with_resources(self, *args, **kwargs):
        return _build_registry().with_resources(*args, **kwargs)
    def with_resource(self, *args, **kwargs):
        return _build_registry().with_resource(*args, **kwargs)


REGISTRY = _LazyRegistry()
